class Solution:
    def bestClosingTime(self, customers: str) -> int:
        n = len(customers)
        penalties = [0] * (n + 1)
        for i in range(n + 1):
            penalty = 0
            for j in range(n):
                if j < i and customers[j] == 'N':
                    penalty += 1
                if j >= i and customers[j] == 'Y':
                    penalty += 1
            penalties[i] = penalty
        min_penalty = min(penalties)
        for i in range(n + 1):
            if penalties[i] == min_penalty:
                return i
```
